import requests
import json
import urllib.parse
from dataclasses import dataclass, field
from typing import Optional


@dataclass
class RabbitMQPermission:
    configure: str = ".*"
    write: str = ".*"
    read: str = ".*"


@dataclass
class RabbitMQUser:
    username: str
    password: str
    tags: str = ""  # "administrator", "monitoring", "management", ""


@dataclass
class RabbitMQVhost:
    name: str
    description: str = ""
    tags: list = field(default_factory=list)


class RabbitMQConfigurator:
    def __init__(self, host: str = "localhost", port: int = 15672,
                 admin_user: str = "guest", admin_password: str = "guest",
                 scheme: str = "http"):
        self.base_url = f"{scheme}://{host}:{port}/api"
        self.session = requests.Session()
        self.session.auth = (admin_user, admin_password)
        self.session.headers.update({"Content-Type": "application/json"})

    def _encode_vhost(self, vhost: str) -> str:
        return urllib.parse.quote(vhost, safe="")

    def _handle_response(self, response: requests.Response, operation: str) -> bool:
        if response.status_code in (200, 201, 204):
            print(f"  ✓ {operation} - SUCCESS")
            return True
        else:
            print(f"  ✗ {operation} - FAILED (HTTP {response.status_code}: {response.text})")
            return False

    # --- Health & Info ---

    def check_connection(self) -> bool:
        try:
            resp = self.session.get(f"{self.base_url}/overview", timeout=5)
            if resp.status_code == 200:
                info = resp.json()
                print(f"Connected to RabbitMQ {info.get('rabbitmq_version', 'unknown')} "
                      f"on cluster '{info.get('cluster_name', 'unknown')}'")
                return True
            else:
                print(f"Failed to connect: HTTP {resp.status_code}")
                return False
        except requests.ConnectionError as e:
            print(f"Connection error: {e}")
            return False

    def list_vhosts(self) -> list:
        resp = self.session.get(f"{self.base_url}/vhosts")
        if resp.status_code == 200:
            return resp.json()
        return []

    def list_users(self) -> list:
        resp = self.session.get(f"{self.base_url}/users")
        if resp.status_code == 200:
            return resp.json()
        return []

    def list_permissions(self, vhost: Optional[str] = None) -> list:
        if vhost:
            encoded = self._encode_vhost(vhost)
            resp = self.session.get(f"{self.base_url}/vhost/{encoded}/permissions")
        else:
            resp = self.session.get(f"{self.base_url}/permissions")
        if resp.status_code == 200:
            return resp.json()
        return []

    # --- Virtual Host Management ---

    def create_vhost(self, vhost: RabbitMQVhost) -> bool:
        encoded = self._encode_vhost(vhost.name)
        payload = {
            "description": vhost.description,
            "tags": ",".join(vhost.tags) if vhost.tags else ""
        }
        resp = self.session.put(f"{self.base_url}/vhosts/{encoded}", data=json.dumps(payload))
        return self._handle_response(resp, f"Create vhost '{vhost.name}'")

    def delete_vhost(self, vhost_name: str) -> bool:
        encoded = self._encode_vhost(vhost_name)
        resp = self.session.delete(f"{self.base_url}/vhosts/{encoded}")
        return self._handle_response(resp, f"Delete vhost '{vhost_name}'")

    def vhost_exists(self, vhost_name: str) -> bool:
        encoded = self._encode_vhost(vhost_name)
        resp = self.session.get(f"{self.base_url}/vhosts/{encoded}")
        return resp.status_code == 200

    # --- User Management ---

    def create_user(self, user: RabbitMQUser) -> bool:
        payload = {
            "password": user.password,
            "tags": user.tags
        }
        resp = self.session.put(
            f"{self.base_url}/users/{urllib.parse.quote(user.username, safe='')}",
            data=json.dumps(payload)
        )
        return self._handle_response(resp, f"Create user '{user.username}' (tags: '{user.tags}')")

    def delete_user(self, username: str) -> bool:
        resp = self.session.delete(
            f"{self.base_url}/users/{urllib.parse.quote(username, safe='')}"
        )
        return self._handle_response(resp, f"Delete user '{username}'")

    def user_exists(self, username: str) -> bool:
        resp = self.session.get(
            f"{self.base_url}/users/{urllib.parse.quote(username, safe='')}"
        )
        return resp.status_code == 200

    # --- Permission Management ---

    def set_permission(self, vhost_name: str, username: str,
                       permission: RabbitMQPermission) -> bool:
        encoded_vhost = self._encode_vhost(vhost_name)
        encoded_user = urllib.parse.quote(username, safe="")
        payload = {
            "configure": permission.configure,
            "write": permission.write,
            "read": permission.read
        }
        resp = self.session.put(
            f"{self.base_url}/permissions/{encoded_vhost}/{encoded_user}",
            data=json.dumps(payload)
        )
        return self._handle_response(
            resp,
            f"Set permissions for '{username}' on vhost '{vhost_name}' "
            f"(configure='{permission.configure}', write='{permission.write}', read='{permission.read}')"
        )

    def clear_permission(self, vhost_name: str, username: str) -> bool:
        encoded_vhost = self._encode_vhost(vhost_name)
        encoded_user = urllib.parse.quote(username, safe="")
        resp = self.session.delete(
            f"{self.base_url}/permissions/{encoded_vhost}/{encoded_user}"
        )
        return self._handle_response(resp, f"Clear permissions for '{username}' on vhost '{vhost_name}'")

    # --- Topic Permission Management ---

    def set_topic_permission(self, vhost_name: str, username: str,
                             exchange: str, write: str = ".*", read: str = ".*") -> bool:
        encoded_vhost = self._encode_vhost(vhost_name)
        encoded_user = urllib.parse.quote(username, safe="")
        payload = {
            "exchange": exchange,
            "write": write,
            "read": read
        }
        resp = self.session.put(
            f"{self.base_url}/topic-permissions/{encoded_vhost}/{encoded_user}",
            data=json.dumps(payload)
        )
        return self._handle_response(
            resp,
            f"Set topic permissions for '{username}' on vhost '{vhost_name}' exchange '{exchange}'"
        )

    # --- Policy Management ---

    def set_policy(self, vhost_name: str, policy_name: str, pattern: str,
                   definition: dict, priority: int = 0,
                   apply_to: str = "all") -> bool:
        encoded_vhost = self._encode_vhost(vhost_name)
        encoded_policy = urllib.parse.quote(policy_name, safe="")
        payload = {
            "pattern": pattern,
            "definition": definition,
            "priority": priority,
            "apply-to": apply_to
        }
        resp = self.session.put(
            f"{self.base_url}/policies/{encoded_vhost}/{encoded_policy}",
            data=json.dumps(payload)
        )
        return self._handle_response(
            resp, f"Set policy '{policy_name}' on vhost '{vhost_name}'"
        )

    # --- Exchange & Queue Creation ---

    def create_exchange(self, vhost_name: str, exchange_name: str,
                        exchange_type: str = "topic", durable: bool = True,
                        auto_delete: bool = False, arguments: Optional[dict] = None) -> bool:
        encoded_vhost = self._encode_vhost(vhost_name)
        encoded_exchange = urllib.parse.quote(exchange_name, safe="")
        payload = {
            "type": exchange_type,
            "durable": durable,
            "auto_delete": auto_delete,
            "arguments": arguments or {}
        }
        resp = self.session.put(
            f"{self.base_url}/exchanges/{encoded_vhost}/{encoded_exchange}",
            data=json.dumps(payload)
        )
        return self._handle_response(
            resp, f"Create exchange '{exchange_name}' (type={exchange_type}) on vhost '{vhost_name}'"
        )

    def create_queue(self, vhost_name: str, queue_name: str,
                     durable: bool = True, auto_delete: bool = False,
                     arguments: Optional[dict] = None) -> bool:
        encoded_vhost = self._encode_vhost(vhost_name)
        encoded_queue = urllib.parse.quote(queue_name, safe="")
        payload = {
            "durable": durable,
            "auto_delete": auto_delete,
            "arguments": arguments or {}
        }
        resp = self.session.put(
            f"{self.base_url}/queues/{encoded_vhost}/{encoded_queue}",
            data=json.dumps(payload)
        )
        return self._handle_response(
            resp, f"Create queue '{queue_name}' on vhost '{vhost_name}'"
        )

    def create_binding(self, vhost_name: str, exchange_name: str,
                       queue_name: str, routing_key: str = "",
                       arguments: Optional[dict] = None) -> bool:
        encoded_vhost = self._encode_vhost(vhost_name)
        encoded_exchange = urllib.parse.quote(exchange_name, safe="")
        encoded_queue = urllib.parse.quote(queue_name, safe="")
        payload = {
            "routing_key": routing_key,
            "arguments": arguments or {}
        }
        resp = self.session.post(
            f"{self.base_url}/bindings/{encoded_vhost}/e/{encoded_exchange}/q/{encoded_queue}",
            data=json.dumps(payload)
        )
        return self._handle_response(
            resp,
            f"Bind queue '{queue_name}' to exchange '{exchange_name}' "
            f"with key '{routing_key}' on vhost '{vhost_name}'"
        )

    # --- High-Level Configuration ---

    def configure_tenant(self, tenant_name: str, description: str,
                         users: list, exchanges: Optional[list] = None,
                         queues: Optional[list] = None,
                         bindings: Optional[list] = None,
                         policies: Optional[list] = None):
        """
        Configure a complete tenant environment with vhost, users, permissions,
        exchanges, queues, bindings, and policies.
        """
        print(f"\n{'='*60}")
        print(f"Configuring tenant: {tenant_name}")
        print(f"{'='*60}")

        # Create vhost
        vhost = RabbitMQVhost(
            name=tenant_name,
            description=description,
            tags=["multi-tenant"]
        )
        self.create_vhost(vhost)

        # Create users and set permissions
        for user_config in users:
            user = RabbitMQUser(
                username=user_config["username"],
                password=user_config["password"],
                tags=user_config.get("tags", "")
            )
            self.create_user(user)

            perm_config = user_config.get("permissions", {})
            permission = RabbitMQPermission(
                configure=perm_config.get("configure", ".*"),
                write=perm_config.get("write", ".*"),
                read=perm_config.get("read", ".*")
            )
            self.set_permission(tenant_name, user.username, permission)

        # Create exchanges
        if exchanges:
            for exc in exchanges:
                self.create_exchange(
                    vhost_name=tenant_name,
                    exchange_name=exc["name"],
                    exchange_type=exc.get("type", "topic"),
                    durable=exc.get("durable", True),
                    arguments=exc.get("arguments")
                )

        # Create queues
        if queues:
            for q in queues:
                self.create_queue(
                    vhost_name=tenant_name,
                    queue_name=q["name"],
                    durable=q.get("durable", True),
                    arguments=q.get("arguments")
                )

        # Create bindings
        if bindings:
            for b in bindings:
                self.create_binding(
                    vhost_name=tenant_name,
                    exchange_name=b["exchange"],
                    queue_name=b["queue"],
                    routing_key=b.get("routing_key", "")
                )

        # Set policies
        if policies:
            for p in policies:
                self.set_policy(
                    vhost_name=tenant_name,
                    policy_name=p["name"],
                    pattern=p["pattern"],
                    definition=p["definition"],
                    priority=p.get("priority", 0),
                    apply_to=p.get("apply_to", "all")
                )

    def print_status(self):
        """Print current RabbitMQ configuration status."""
        print(f"\n{'='*60}")
        print("Current RabbitMQ Configuration Status")
        print(f"{'='*60}")

        # List vhosts
        vhosts = self.list_vhosts()
        print(f"\nVirtual Hosts ({len(vhosts)}):")
        for vh in vhosts:
            print(f"  - {vh['name']} (description: {vh.get('description', 'N/A')})")

        # List users
        users = self.list_users()
        print(f"\nUsers ({len(users)}):")
        for u in users:
            print(f"  - {u['name']} (tags: {u.get('tags', 'none')})")

        # List permissions
        permissions = self.list_permissions()
        print(f"\nPermissions ({len(permissions)}):")
        for p in permissions:
            print(f"  - User '{p['user']}' on vhost '{p['vhost']}': "
                  f"configure='{p['configure']}', write='{p['write']}', read='{p['read']}'")


